// migrate.js
const fs = require('fs');
const path = require('path');

// Directory containing migration files
const migrationsDir = path.join(__dirname, 'migrations');

// Read all files from the migrations directory
fs.readdir(migrationsDir, (err, files) => {
  if (err) {
    console.error('Error reading migrations directory:', err);
    return;
  }

  // Filter for SQL files and sort them to ensure correct order
  const sqlFiles = files
    .filter(file => path.extname(file).toLowerCase() === '.sql')
    .sort(); // Sort alphabetically, assuming files are named like 001_..., 002_...

  // Log each migration file that would be applied
  console.log('Applying migrations:');
  sqlFiles.forEach(file => {
    console.log(`- Applying migration: ${file}`);
    // Here you would normally execute the SQL file
  });

  if (sqlFiles.length === 0) {
    console.log('No migration files found.');
  }
});

