const fs = require('fs');
const path = require('path');

// Simple .env file parser
function loadEnv(envFile) {
  try {
    const content = fs.readFileSync(envFile, 'utf8');
    const env = {};
    content.split('\n').forEach(line => {
      // Match key=value lines, ignoring comments and empty lines
      const match = line.match(/^([^#]+?)=(.*)$/);
      if (match) {
        const key = match[1].trim();
        let value = match[2].trim();
        // Remove surrounding quotes if present
        if (/^"(.*)"$/.test(value) || /^'(.*)'$/.test(value)) {
          value = value.slice(1, -1);
        }
        env[key] = value;
      }
    });
    return env;
  } catch (err) {
    if (err.code === 'ENOENT') {
      console.error(`${envFile} not found`);
    } else {
      console.error(`Error reading ${envFile}:`, err);
    }
    return {};
  }
}

// Load environment variables
const env = loadEnv('.env.test');
const databaseUrl = env.DATABASE_URL;

if (!databaseUrl) {
  console.error('DATABASE_URL not found in .env.test');
  process.exit(1);
}

console.log('Found database connection string in .env.test');
