// Function to read and apply migrations
function runMigrations() {
  // Check if migrations directory exists
  if (!fs.existsSync(MIGRATIONS_DIR)) {
    console.log(`Migrations directory ${MIGRATIONS_DIR} does not exist.`);
    return;
  }

  // Read all files from the migrations directory
  fs.readdir(MIGRATIONS_DIR, (err, files) => {
    if (err) {
      console.error(`Error reading migrations directory: ${err}`);
      return;
    }

    // Filter only SQL files and sort them to ensure correct order
    const sqlFiles = files
